  List<ThreadActivityItem> _mergeTimeline(
    List<ThreadTimelineEntryDto> timeline,
  ) {
    final nextItems = _mergeTimelineEntries(
      currentItems: state.items,
      timeline: timeline,
    );
    _trackKnownEventIds(nextItems);
    return nextItems;
