Future<void> _assertSingleUserPromptInSnapshot({
  required String bridgeApiBaseUrl,
  required String threadId,
  required String expectedPrompt,
}) async {
  final snapshot = await _fetchThreadSnapshotJson(
    bridgeApiBaseUrl: bridgeApiBaseUrl,
    threadId: threadId,
  );
  final entries = snapshot['entries'] as List<dynamic>? ?? const [];
  final matchingUserPrompts = entries.where((entry) {
    if (entry is! Map<String, dynamic>) {
      return false;
    }
    final payload = entry['payload'];
    if (payload is! Map<String, dynamic>) {
      return false;
    }
    final role = (payload['role'] as String?)?.trim();
    final text =
        ((payload['text'] ?? payload['delta'] ?? payload['message']) as String?)
            ?.trim();
    return role == 'user' && text == expectedPrompt;
  }).length;

  expect(
    matchingUserPrompts,
    1,
    reason:
        'Expected exactly one visible user prompt for $threadId in the final '
        'snapshot, but found $matchingUserPrompts.',
  );
}

Future<Map<String, dynamic>> _fetchThreadSnapshotJson({
  required String bridgeApiBaseUrl,
  required String threadId,
}) async {
  final client = HttpClient()..connectionTimeout = const Duration(seconds: 8);
  try {
    final request = await client.getUrl(
      _buildBridgeUri(bridgeApiBaseUrl, '/threads/$threadId/snapshot'),
    );
    request.headers.set(HttpHeaders.acceptHeader, 'application/json');
    final response = await request.close();
    final body = await utf8.decoder.bind(response).join();
    if (response.statusCode < 200 || response.statusCode >= 300) {
      fail(
        'Snapshot request for $threadId failed with ${response.statusCode}: $body',
      );
    }
    final decoded = jsonDecode(body);
    if (decoded is! Map<String, dynamic>) {
      fail('Snapshot response for $threadId was not a JSON object: $decoded');
    }
    return decoded;
  } finally {
    client.close(force: true);
  }
}

Uri _buildBridgeUri(String baseUrl, String path) {
  final baseUri = Uri.parse(baseUrl);
  final normalizedBasePath = baseUri.path.endsWith('/')
      ? baseUri.path.substring(0, baseUri.path.length - 1)
      : baseUri.path;
  final normalizedPath = path.startsWith('/') ? path : '/$path';
  return baseUri.replace(
    path:
        '${normalizedBasePath.isEmpty ? '' : normalizedBasePath}$normalizedPath',
  );
}

