        .get("reason")
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_string();
    let target = payload
        .get("target")
        .and_then(Value::as_str)
        .map(str::to_string)
        .filter(|value| !value.trim().is_empty());

    Some(ApprovalSummaryDto {
        approval_id,
        thread_id: thread_id.to_string(),
        action,
        status,
        reason,
        target,
    })
}

fn parse_approval_status(raw: &str) -> ApprovalStatus {
